                <td style="text-align: center;">
                    {{ item.qty }}
                </td>
                <td style="text-align: center;">
                    {{ item.uom }}&nbsp;
                </td>
    <td style="text-align: right;width:10%;">
    {% if item.rate %}
    {{ item.get_formatted("rate") }}
    {% endif %}
    </td>
    <td style="text-align: right;">
    {% if item.item_tax_template %}
    {%set c=frappe.get_doc("Item Tax Template", item.item_tax_template)%}
    {{c.title[4:6]}}%
    {% endif %}
   </td>
                <td style="text-align: right;width:12%;">{{ item.get_formatted("amount") }}</td>
            </tr>
            {%- endfor -%}
            <tr>
                <th colspan="8"></th>
                <th style="text-align: center;"><b>{{ _("Total") }}</b></th>
                <th style="text-align: right;width:12%;"><b>{{ doc.get_formatted("total") }}</b></th>
            </tr>
        </table>
    {% endif %}

<table style="margin-top: 10px; width: 100%; border-collapse: collapse;">
    <tr>
        <td rowspan="10" style="width:57%; vertical-align: top;">
            <b>Total Amount in Words:</b><br>
            {{ doc.in_words }}
        </td>
        <td style="width:28%;" class="text-right">
            <b>Total Amount:</b>
        </td>
        <td style="width:15%;" class="text-right">
            {{ doc.get_formatted("total") }}
        </td>
    </tr>

    {% if doc.additional_discount_percentage %}
    <tr>
        <td class="text-right">
            <b>Additional Disc. on {{ doc.apply_discount_on }}: {{ doc.additional_discount_percentage }}%</b>
        </td>
        <td class="text-right">
            - {{ doc.get_formatted("discount_amount") }}
        </td>
    </tr>
    {% endif %}

    <tr>
        <td class="text-right"><b>Taxable Value:</b></td>
        <td class="text-right">{{ doc.get_formatted("net_total") }}</td>
    </tr>

    {% for tax in doc.taxes %}
    <tr>
        <td class="text-right"><b>{{ tax.description }}</b></td>
        <td class="text-right">{{ tax.get_formatted("tax_amount") }}</td>
    </tr>
    {% endfor %}

    <tr>
        <td class="text-right"><b>Total:</b></td>
        <td class="text-right">{{ doc.get_formatted("grand_total") }}</td>
    </tr>

    <tr>
        <td class="text-right"><b>Round Off Amount:</b></td>
        <td class="text-right">{{ doc.get_formatted("rounding_adjustment") }}</td>
    </tr>

    <tr>
        <td class="text-right"><b>Invoice Value:</b></td>
        <td class="text-right">{{ doc.get_formatted("rounded_total") }}</td>
    </tr>
</table>
    {% if doc.other_charges_calculation %}
    <div style="margin-top: -15px; margin-bottom: -15px;">{{ doc.other_charges_calculation }} </div>
    {% endif %}

